export const NeonSignWriter: React.FC<any> = (props) => {
  const {
    position = { x: 0.1, y: 0.3, w: 0.8, h: 0.3 },
    text = "Everything I'm not makes me everything I am",
    neonColor = "#FF2D95",
    secondaryColor = "#00F0FF",
    fontSize = 72,
  } = props;

  const frame = useCurrentFrame();
  const { fps, durationInFrames, width, height } = useVideoConfig();

  // Fade out in last 0.5 seconds
  const fadeOutStart = durationInFrames - Math.round(fps * 0.5);
  const exitOpacity = interpolate(
    frame,
    [fadeOutStart, durationInFrames],
    [1, 0],
    { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
  );

  const left = position.x * width;
  const top = position.y * height;
  const maxWidth = position.w * width;
  const maxHeight = position.h * height;

  const letters = text.split("");
  const totalLetters = letters.length;

  // Timing
  const framesPerLetter = Math.max(3, Math.floor((durationInFrames * 0.5) / totalLetters));
  const flickerDuration = Math.round(fps * 0.3);
  const allLettersDone = totalLetters * framesPerLetter + flickerDuration;

  // Pulse phase (after all letters lit)
  const pulseActive = frame > allLettersDone;
  const pulseT = pulseActive ? (frame - allLettersDone) / fps : 0;
  const pulseIntensity = pulseActive
    ? 1 + 0.15 * Math.sin(pulseT * Math.PI * 2 * 1.5) + 0.05 * Math.sin(pulseT * Math.PI * 2 * 4.7)
    : 1;

  // Pseudo-random for flicker (deterministic based on index + frame)
  const pseudoRandom = (seed: number, f: number) => {
    const x = Math.sin(seed * 127.1 + f * 311.7) * 43758.5453;
    return x - Math.floor(x);
  };

  const getLetterState = (index: number) => {
    const letterStart = index * framesPerLetter;
    const localFrame = frame - letterStart;

    if (localFrame < 0) return { opacity: 0, phase: "hidden" as const };

    // Flicker phase: letter is "wiring up"
    if (localFrame < flickerDuration) {
      const flickerProgress = localFrame / flickerDuration;
      // More flickers early, stabilizing toward end
      const flickerRate = interpolate(flickerProgress, [0, 1], [0.3, 0.9], {
        extrapolateLeft: "clamp",
        extrapolateRight: "clamp",
      });
      const rand = pseudoRandom(index, localFrame);
      const isOn = rand < flickerRate;
      const brightness = isOn
        ? interpolate(flickerProgress, [0, 1], [0.4, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" })
        : 0.05;
      return { opacity: brightness, phase: "flickering" as const };
    }

    // Lit phase
    return { opacity: 1, phase: "lit" as const };
  };

  // Glow sizes
  const baseGlow = fontSize * 0.15;
  const strongGlow = fontSize * 0.4;
  const bleedGlow = fontSize * 0.8;

  // Overall entrance spring
  const entranceProgress = spring({
    frame,
    fps,
    config: { damping: 20, mass: 0.5, stiffness: 200 },
  });

  const containerScale = interpolate(entranceProgress, [0, 1], [0.95, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  return (
    <div
      style={{
        position: "absolute",
        left,
        top,
        maxWidth,
        maxHeight,
        overflow: "visible",
        opacity: exitOpacity,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        transform: `scale(${containerScale})`,
        transformOrigin: "center center",
      }}
    >
      {/* Light bleed / ambient glow behind text */}
      {pulseActive && (
        <div
          style={{
            position: "absolute",
            left: "50%",
            top: "50%",
            transform: "translate(-50%, -50%)",
            width: maxWidth * 0.9,
            height: fontSize * 2.5,
            borderRadius: "50%",
            background: `radial-gradient(ellipse at center, ${neonColor}22 0%, ${neonColor}08 40%, transparent 70%)`,
            opacity: interpolate(pulseIntensity, [0.85, 1.15], [0.4, 0.8], {
              extrapolateLeft: "clamp",
              extrapolateRight: "clamp",
            }),
            pointerEvents: "none",
          }}
        />
      )}

      <div
        style={{
          display: "flex",
          flexWrap: "nowrap",
          alignItems: "center",
          justifyContent: "center",
          gap: 0,
        }}
      >
        {letters.map((letter, index) => {
          const { opacity, phase } = getLetterState(index);

          if (letter === " ") {
            return (
              <span
                key={index}
                style={{
                  display: "inline-block",
                  width: fontSize * 0.3,
                }}
              />
            );
          }

          const isLit = phase === "lit";
          const isFlickering = phase === "flickering";
          const currentPulse = isLit ? pulseIntensity : 1;

          // Color shift: slight hue variation per letter for depth
          const hueShift = (index / totalLetters) * 10 - 5;

          // Flicker color: dimmer, more toward secondary
          const currentColor = isFlickering && opacity < 0.5 ? secondaryColor : neonColor;

          const glowMultiplier = opacity * currentPulse;

          const textShadowLayers = [
            // Inner glow (tight)
            `0 0 ${baseGlow * glowMultiplier}px ${currentColor}`,
            // Medium glow
            `0 0 ${strongGlow * glowMultiplier}px ${currentColor}`,
            // Outer bleed
            `0 0 ${bleedGlow * glowMultiplier}px ${currentColor}66`,
            // Far bleed
            `0 0 ${bleedGlow * 1.5 * glowMultiplier}px ${currentColor}22`,
            // White-hot core
            `0 0 ${baseGlow * 0.3 * glowMultiplier}px #FFFFFF`,
          ].join(", ");

          // Stroke draw effect: clip-path reveal for letters not yet fully visible
          const strokeProgress = phase === "hidden"
            ? 0
            : isFlickering
              ? interpolate(
                  frame - index * framesPerLetter,
                  [0, flickerDuration],
                  [0.3, 1],
                  { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
                )
              : 1;

          return (
            <span
              key={index}
              style={{
                display: "inline-block",
                fontSize,
                fontFamily: "'Arial Black', 'Impact', sans-serif",
                fontWeight: 900,
                color: `rgba(255, 255, 255, ${opacity * 0.95})`,
                textShadow: opacity > 0.05 ? textShadowLayers : "none",
                opacity: phase === "hidden" ? 0 : 1,
                filter: `brightness(${interpolate(opacity, [0, 1], [0.2, 1.2], { extrapolateLeft: "clamp", extrapolateRight: "clamp" })}) hue-rotate(${hueShift}deg)`,
                transition: "none",
                letterSpacing: fontSize * 0.05,
                WebkitTextStroke: opacity > 0.3
                  ? `1px ${currentColor}`
                  : `1px ${currentColor}44`,
                transform: isFlickering && opacity < 0.4
                  ? `scaleY(${0.97 + pseudoRandom(index, frame) * 0.06})`
                  : "none",
                clipPath: strokeProgress < 1
                  ? `inset(0 ${(1 - strokeProgress) * 100}% 0 0)`
                  : "none",
              }}
            >
              {letter}
            </span>
          );
        })}
      </div>

      {/* Reflection / under-glow */}
      <div
        style={{
          position: "absolute",
          bottom: -fontSize * 0.6,
          left: "50%",
          transform: "translate(-50%, 0) scaleY(-1)",
          display: "flex",
          flexWrap: "nowrap",
          alignItems: "center",
          justifyContent: "center",
          opacity: 0.12 * (pulseActive ? pulseIntensity : interpolate(
            frame,
            [0, allLettersDone],
            [0, 1],
            { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
          )),
          filter: `blur(${fontSize * 0.15}px)`,
          maskImage: "linear-gradient(to bottom, rgba(0,0,0,0.6) 0%, transparent 80%)",
          WebkitMaskImage: "linear-gradient(to bottom, rgba(0,0,0,0.6) 0%, transparent 80%)",
          pointerEvents: "none",
        }}
      >
        {letters.map((letter, index) => {
          const { opacity } = getLetterState(index);
          if (letter === " ") {
            return (
              <span
                key={`r-${index}`}
                style={{ display: "inline-block", width: fontSize * 0.3 }}
              />
            );
          }
          return (
            <span
              key={`r-${index}`}
              style={{
                display: "inline-block",
                fontSize,
                fontFamily: "'Arial Black', 'Impact', sans-serif",
                fontWeight: 900,
                color: neonColor,
                opacity,
                textShadow: `0 0 ${strongGlow}px ${neonColor}`,
                letterSpacing: fontSize * 0.05,
              }}
            >
              {letter}
            </span>
          );
        })}
      </div>

      {/* Tiny wire/connector lines between letters — decorative */}
      <svg
        style={{
          position: "absolute",
          top: -fontSize * 0.3,
          left: 0,
          width: "100%",
          height: fontSize * 0.3,
          overflow: "visible",
          pointerEvents: "none",
        }}
      >
        {letters.map((letter, index) => {
          if (letter === " " || index === 0) return null;
          const { phase } = getLetterState(index);
          if (phase === "hidden") return null;

          const wireOpacity = phase === "lit" ? 0.3 * pulseIntensity : 0.15;
          const xStart = ((index - 0.5) / totalLetters) * 100;
          const xEnd = ((index + 0.5) / totalLetters) * 100;

          return (
            <line
              key={`w-${index}`}
              x1={`${xStart}%`}
              y1="100%"
              x2={`${xEnd}%`}
              y2={`${80 + pseudoRandom(index, 0) * 20}%`}
              stroke={neonColor}
              strokeWidth={1}
              opacity={wireOpacity}
              strokeDasharray={phase === "flickering" ? "3 3" : "none"}
            />
          );
        })}
      </svg>
    </div>
  );
};

