export const CakeAnimation: React.FC<any> = (props) => {
  const { position = { x: 0.25, y: 0.2, w: 0.5, h: 0.6 } } = props;
  const frame = useCurrentFrame();
  const { fps, durationInFrames, width, height } = useVideoConfig();

  const fadeOutStart = durationInFrames - Math.round(fps * 0.5);
  const exitOpacity = interpolate(
    frame,
    [fadeOutStart, durationInFrames],
    [1, 0],
    { extrapolateLeft: "clamp", extrapolateRight: "clamp" },
  );

  const left = position.x * width;
  const top = position.y * height;
  const maxWidth = position.w * width;
  const maxHeight = position.h * height;

  // Spring entrance
  const entranceProgress = spring({
    frame,
    fps,
    config: { damping: 15, mass: 0.8, stiffness: 80 },
  });

  const scaleY = interpolate(entranceProgress, [0, 1], [0, 1]);
  const overallOpacity = interpolate(entranceProgress, [0, 0.3], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  // Colors
  const cakeBottom = "#8B4513";
  const cakeMid = "#D2691E";
  const cakeTop = "#F5DEB3";
  const frosting = "#FFB6C1";
  const frostingDrip = "#FF69B4";
  const cherryColor = "#DC143C";
  const candleColor = "#FFFACD";
  const candleBody = "#FF6347";
  const plateColor = "#E8E8E8";

  // Flame flicker
  const flickerX = Math.sin(frame * 0.5) * 2;
  const flickerScale = 0.9 + Math.sin(frame * 0.7) * 0.1;

  // Candle flame appears after cake entrance
  const flameDelay = 15;
  const flameProgress = spring({
    frame: Math.max(0, frame - flameDelay),
    fps,
    config: { damping: 10, mass: 0.6, stiffness: 120 },
  });

  // Sparkle particles around the cake
  const sparkles = useMemo(() => {
    return Array.from({ length: 12 }, (_, i) => ({
      x: 30 + (i * 67) % 240,
      y: 20 + (i * 43) % 180,
      delay: i * 4,
      size: 3 + (i % 3) * 2,
    }));
  }, []);

  const svgW = 300;
  const svgH = 320;

  return (
    <div
      style={{
        position: "absolute",
        left,
        top,
        maxWidth,
        maxHeight,
        overflow: "hidden",
        opacity: exitOpacity * overallOpacity,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      <svg
        viewBox={`0 0 ${svgW} ${svgH}`}
        width={Math.min(maxWidth, maxHeight * (svgW / svgH))}
        height={Math.min(maxHeight, maxWidth * (svgH / svgW))}
        style={{
          transform: `scaleY(${scaleY})`,
          transformOrigin: "bottom center",
        }}
      >
        {/* Sparkles */}
        {sparkles.map((sp, i) => {
          const spProgress = spring({
            frame: Math.max(0, frame - sp.delay - 20),
            fps,
            config: { damping: 5, mass: 0.4, stiffness: 300 },
          });
          const spOpacity = interpolate(
            Math.sin(frame * 0.15 + i),
            [-1, 1],
            [0.2, 1],
          );
          return (
            <circle
              key={i}
              cx={sp.x}
              cy={sp.y}
              r={sp.size * spProgress}
              fill="#FFD700"
              opacity={spOpacity * spProgress}
            />
          );
        })}

        {/* Plate / base */}
        <ellipse cx={150} cy={280} rx={130} ry={18} fill={plateColor} opacity={0.9} />
        <ellipse cx={150} cy={280} rx={130} ry={18} fill="none" stroke="#ccc" strokeWidth={1.5} />

        {/* Bottom cake layer */}
        <rect x={60} y={230} width={180} height={50} rx={8} fill={cakeBottom} />
        <rect x={60} y={230} width={180} height={10} rx={4} fill={cakeMid} opacity={0.6} />

        {/* Middle cake layer */}
        <rect x={80} y={185} width={140} height={50} rx={8} fill={cakeMid} />
        <rect x={80} y={185} width={140} height={10} rx={4} fill={cakeTop} opacity={0.5} />

        {/* Top cake layer */}
        <rect x={100} y={145} width={100} height={45} rx={8} fill={cakeTop} />

        {/* Frosting on top layer */}
        <ellipse cx={150} cy={148} rx={52} ry={8} fill={frosting} />

        {/* Frosting drips */}
        {[110, 130, 150, 170, 190].map((dx, i) => {
          const dripH = 12 + (i % 3) * 8;
          const dripProgress = spring({
            frame: Math.max(0, frame - 8 - i * 3),
            fps,
            config: { damping: 15, mass: 0.8, stiffness: 80 },
          });
          return (
            <rect
              key={i}
              x={dx - 4}
              y={145}
              width={8}
              height={dripH * dripProgress}
              rx={4}
              fill={frostingDrip}
              opacity={0.85}
            />
          );
        })}

        {/* Frosting drips on middle layer */}
        {[90, 115, 140, 165, 195, 210].map((dx, i) => {
          const dripH = 10 + (i % 3) * 6;
          const dripProgress = spring({
            frame: Math.max(0, frame - 5 - i * 2),
            fps,
            config: { damping: 15, mass: 0.8, stiffness: 80 },
          });
          return (
            <rect
              key={`mid-${i}`}
              x={dx - 3}
              y={185}
              width={6}
              height={dripH * dripProgress}
              rx={3}
              fill={frosting}
              opacity={0.7}
            />
          );
        })}

        {/* Candle */}
        <rect x={146} y={105} width={8} height={42} rx={3} fill={candleBody} />
        <rect x={147} y={105} width={2} height={42} rx={1} fill="#FF4500" opacity={0.4} />

        {/* Wick */}
        <line x1={150} y1={105} x2={150} y2={96} stroke="#333" strokeWidth={1.5} />

        {/* Flame */}
        <g
          transform={`translate(${150 + flickerX * flameProgress}, 88) scale(${flickerScale * flameProgress})`}
          opacity={flameProgress}
        >
          {/* Outer flame */}
          <ellipse cx={0} cy={0} rx={7} ry={12} fill="#FFA500" opacity={0.7} />
          {/* Inner flame */}
          <ellipse cx={0} cy={2} rx={4} ry={8} fill={candleColor} opacity={0.9} />
          {/* Core */}
          <ellipse cx={0} cy={4} rx={2} ry={4} fill="#FFFFFF" opacity={0.8} />
        </g>

        {/* Flame glow */}
        <circle
          cx={150}
          cy={88}
          r={25}
          fill="#FFA500"
          opacity={0.08 * flameProgress + Math.sin(frame * 0.5) * 0.03}
        />

        {/* Cherry on top */}
        {(() => {
          const cherryBounce = spring({
            frame: Math.max(0, frame - 12),
            fps,
            config: { damping: 10, mass: 0.6, stiffness: 120 },
          });
          return (
            <g opacity={cherryBounce}>
              <circle
                cx={130}
                cy={142}
                r={7 * cherryBounce}
                fill={cherryColor}
              />
              <ellipse
                cx={128}
                cy={140}
                rx={2}
                ry={1.5}
                fill="white"
                opacity={0.5}
              />
              {/* Stem */}
              <path
                d="M130 135 Q133 128 137 126"
                stroke="#228B22"
                strokeWidth={1.5}
                fill="none"
                opacity={cherryBounce}
              />
            </g>
          );
        })()}

        {/* Decorative dots on bottom layer */}
        {[80, 100, 120, 140, 160, 180, 200, 220].map((dx, i) => {
          const dotProgress = spring({
            frame: Math.max(0, frame - 10 - i * 2),
            fps,
            config: { damping: 10, mass: 0.6, stiffness: 120 },
          });
          return (
            <circle
              key={`dot-${i}`}
              cx={dx}
              cy={255}
              r={3 * dotProgress}
              fill={i % 2 === 0 ? "#FFD700" : frostingDrip}
              opacity={0.8}
            />
          );
        })}

        {/* Decorative dots on middle layer */}
        {[95, 115, 135, 155, 175, 195].map((dx, i) => {
          const dotProgress = spring({
            frame: Math.max(0, frame - 8 - i * 2),
            fps,
            config: { damping: 10, mass: 0.6, stiffness: 120 },
          });
          return (
            <circle
              key={`mdot-${i}`}
              cx={dx}
              cy={210}
              r={2.5 * dotProgress}
              fill={i % 2 === 0 ? frosting : "#FFD700"}
              opacity={0.7}
            />
          );
        })}

        {/* Shadow under plate */}
        <ellipse cx={150} cy={296} rx={100} ry={8} fill="rgba(0,0,0,0.15)" />
      </svg>
    </div>
  );
};

