export const DigitalDecayGrid: React.FC<any> = (props) => {
  const { position = { x: 0, y: 0, w: 1, h: 1 } } = props;
  const frame = useCurrentFrame();
  const { fps, durationInFrames, width, height } = useVideoConfig();

  const COLS = 28;
  const ROWS = 16;
  const CELL_W = (position.w * width) / COLS;
  const CELL_H = (position.h * height) / ROWS;
  const totalCells = COLS * ROWS;

  const fadeOutStart = durationInFrames - Math.round(fps * 0.5);
  const exitOpacity = interpolate(
    frame,
    [fadeOutStart, durationInFrames],
    [1, 0],
    { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
  );

  const progress = frame / durationInFrames;

  const CORRUPTION_START = 0.05;
  const CRITICAL_MASS = 0.6;
  const COMPACT_POINT = 0.8;
  const DETONATE_POINT = 0.85;

  const corruptionSpread = interpolate(
    progress,
    [CORRUPTION_START, CRITICAL_MASS],
    [0, 1],
    { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
  );

  const collapseProgress = interpolate(
    progress,
    [CRITICAL_MASS, COMPACT_POINT],
    [0, 1],
    { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
  );

  const compactVibrate = interpolate(
    progress,
    [COMPACT_POINT, DETONATE_POINT],
    [0, 1],
    { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
  );

  const detonateProgress = interpolate(
    progress,
    [DETONATE_POINT, 0.98],
    [0, 1],
    { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
  );

  const isCompactPhase = progress >= COMPACT_POINT && progress < DETONATE_POINT;
  const isDetonatePhase = progress >= DETONATE_POINT;

  const seedRng = useMemo(() => {
    const seeds: number[] = [];
    let s = 42;
    for (let i = 0; i < totalCells * 6; i++) {
      s = (s * 16807 + 7) % 2147483647;
      seeds.push((s & 0x7fffffff) / 2147483647);
    }
    return seeds;
  }, [totalCells]);

  const rng = (idx: number) => seedRng[idx % seedRng.length];

  const ORIGIN_COL = Math.floor(COLS * 0.4);
  const ORIGIN_ROW = Math.floor(ROWS * 0.35);

  const centerX = (position.w * width) / 2;
  const centerY = (position.h * height) / 2;

  const sterileColors = ["#E8E8E8", "#D0D0D0", "#C0C0C0", "#B8B8B8", "#CCCCCC"];
  const corruptColors = ["#39FF14", "#FF006E", "#FF6B00", "#00FFFF", "#FF00FF", "#ADFF2F", "#FF1493", "#FF4500"];
  const postColors = ["#E0E8E0", "#D0C8D8", "#C8D0C0", "#B8C0B8", "#D0D0C0", "#C8C0D0"];

  const cells = useMemo(() => {
    return Array.from({ length: totalCells }, (_, i) => {
      const col = i % COLS;
      const row = Math.floor(i / COLS);
      const dist = Math.sqrt((col - ORIGIN_COL) ** 2 + (row - ORIGIN_ROW) ** 2);
      const maxDist = Math.sqrt(COLS * COLS + ROWS * ROWS);
      const normalizedDist = dist / maxDist;
      const corruptThreshold = normalizedDist * 0.85 + rng(i) * 0.15;
      const behavior = Math.floor(rng(i * 3 + 1) * 4);
      const sterileColor = sterileColors[Math.floor(rng(i * 2) * sterileColors.length)];
      const corruptColor = corruptColors[Math.floor(rng(i * 5 + 2) * corruptColors.length)];
      const postColor = postColors[Math.floor(rng(i * 7 + 3) * postColors.length)];
      const repairChance = rng(i * 4 + 10) > 0.75;
      const repairFrame = 0.3 + rng(i * 6 + 20) * 0.25;

      return { col, row, dist, normalizedDist, corruptThreshold, behavior, sterileColor, corruptColor, postColor, repairChance, repairFrame };
    });
  }, [totalCells]);

  const left = position.x * width;
  const top = position.y * height;
  const maxWidth = position.w * width;
  const maxHeight = position.h * height;

  if (isCompactPhase) {
    const vibIntensity = compactVibrate * 8;
    const vx = Math.sin(frame * 1.7) * vibIntensity;
    const vy = Math.cos(frame * 2.3) * vibIntensity;
    const pixelSize = interpolate(compactVibrate, [0, 1], [12, 4], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
    const glowSize = interpolate(compactVibrate, [0, 1], [20, 60], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });

    return (
      <div style={{ position: "absolute", left, top, width: maxWidth, height: maxHeight, overflow: "hidden", opacity: exitOpacity }}>
        <div style={{
          position: "absolute",
          left: centerX + vx - pixelSize / 2,
          top: centerY + vy - pixelSize / 2,
          width: pixelSize,
          height: pixelSize,
          backgroundColor: "#FFFFFF",
          boxShadow: `0 0 ${glowSize}px ${glowSize / 2}px #39FF14, 0 0 ${glowSize * 2}px ${glowSize}px #FF006E`,
        }} />
      </div>
    );
  }

  if (isDetonatePhase) {
    const reformSpring = spring({
      frame: frame - Math.round(DETONATE_POINT * durationInFrames),
      fps,
      config: { damping: 15, mass: 0.8, stiffness: 80 },
    });

    const flashOpacity = interpolate(
      progress,
      [DETONATE_POINT, DETONATE_POINT + 0.03],
      [1, 0],
      { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
    );

    return (
      <div style={{ position: "absolute", left, top, width: maxWidth, height: maxHeight, overflow: "hidden", opacity: exitOpacity }}>
        <div style={{
          position: "absolute",
          left: 0, top: 0, width: maxWidth, height: maxHeight,
          backgroundColor: "#FFFFFF",
          opacity: flashOpacity,
          zIndex: 10,
        }} />
        {cells.map((cell, i) => {
          const targetX = cell.col * CELL_W;
          const targetY = cell.row * CELL_H;

          const angle = Math.atan2(targetY + CELL_H / 2 - centerY, targetX + CELL_W / 2 - centerX);
          const cellDist = Math.sqrt((targetX + CELL_W / 2 - centerX) ** 2 + (targetY + CELL_H / 2 - centerY) ** 2);
          const explosionDist = cellDist * 1.5;

          const fromX = centerX + Math.cos(angle) * explosionDist * (1 - reformSpring) - CELL_W / 2;
          const fromY = centerY + Math.sin(angle) * explosionDist * (1 - reformSpring) - CELL_H / 2;

          const cellX = interpolate(reformSpring, [0, 1], [fromX, targetX]);
          const cellY = interpolate(reformSpring, [0, 1], [fromY, targetY]);
          const cellScale = interpolate(reformSpring, [0, 0.3, 1], [0.2, 1.3, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
          const rotation = interpolate(reformSpring, [0, 1], [rng(i * 9) * 720 - 360, 0]);
          const cellOpacity = interpolate(reformSpring, [0, 0.2, 1], [0, 1, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });

          return (
            <div key={i} style={{
              position: "absolute",
              left: cellX,
              top: cellY,
              width: CELL_W - 1,
              height: CELL_H - 1,
              backgroundColor: cell.postColor,
              transform: `scale(${cellScale}) rotate(${rotation}deg)`,
              opacity: cellOpacity,
              borderRadius: 1,
            }} />
          );
        })}
      </div>
    );
  }

  return (
    <div style={{ position: "absolute", left, top, width: maxWidth, height: maxHeight, overflow: "hidden", opacity: exitOpacity }}>
      {cells.map((cell, i) => {
        const isCorrupted = corruptionSpread > cell.corruptThreshold;
        const corruptionAge = isCorrupted
          ? interpolate(corruptionSpread, [cell.corruptThreshold, Math.min(cell.corruptThreshold + 0.15, 1)], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" })
          : 0;

        const isRepairing = cell.repairChance && isCorrupted && progress > cell.repairFrame && progress < cell.repairFrame + 0.06;

        let baseX = cell.col * CELL_W;
        let baseY = cell.row * CELL_H;

        if (collapseProgress > 0) {
          const toX = centerX - CELL_W / 2;
          const toY = centerY - CELL_H / 2;
          const cellCollapse = interpolate(
            collapseProgress,
            [Math.max(0, 1 - cell.normalizedDist - 0.3), 1],
            [0, 1],
            { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
          );
          baseX = interpolate(cellCollapse, [0, 1], [baseX, toX]);
          baseY = interpolate(cellCollapse, [0, 1], [baseY, toY]);
        }

        if (!isCorrupted) {
          return (
            <div key={i} style={{
              position: "absolute",
              left: baseX,
              top: baseY,
              width: CELL_W - 1,
              height: CELL_H - 1,
              backgroundColor: cell.sterileColor,
              borderRadius: 1,
              transition: "none",
            }} />
          );
        }

        if (isRepairing) {
          const repairLocal = interpolate(
            progress,
            [cell.repairFrame, cell.repairFrame + 0.02, cell.repairFrame + 0.04, cell.repairFrame + 0.06],
            [0, 1, 1, 0],
            { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
          );
          const snapScale = interpolate(repairLocal, [0, 0.5, 1], [1.3, 0.9, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
          return (
            <div key={i} style={{
              position: "absolute",
              left: baseX,
              top: baseY,
              width: CELL_W - 1,
              height: CELL_H - 1,
              backgroundColor: repairLocal > 0.3 ? cell.sterileColor : cell.corruptColor,
              transform: `scale(${snapScale})`,
              borderRadius: 1,
              boxShadow: repairLocal > 0.3 ? "0 0 8px 2px rgba(255,255,255,0.6)" : "none",
            }} />
          );
        }

        const behavior = cell.behavior;

        if (behavior === 0) {
          const meltY = corruptionAge * CELL_H * 3;
          const meltScaleY = 1 + corruptionAge * 2;
          const meltScaleX = 1 - corruptionAge * 0.3;
          const meltOpacity = interpolate(corruptionAge, [0.7, 1], [1, 0.4], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
          return (
            <div key={i} style={{
              position: "absolute",
              left: baseX,
              top: baseY + meltY,
              width: CELL_W - 1,
              height: CELL_H - 1,
              backgroundColor: cell.corruptColor,
              transform: `scaleX(${meltScaleX}) scaleY(${meltScaleY})`,
              transformOrigin: "top center",
              opacity: meltOpacity,
              borderRadius: `0 0 ${corruptionAge * 4}px ${corruptionAge * 4}px`,
            }} />
          );
        }

        if (behavior === 1) {
          const numFragments = 4;
          const fragSize = (CELL_W - 1) / 2;
          return (
            <React.Fragment key={i}>
              {Array.from({ length: numFragments }, (_, fi) => {
                const fAngle = (fi / numFragments) * Math.PI * 2 + rng(i * 11 + fi) * 1.5;
                const fDist = corruptionAge * 20 * (1 + rng(i * 13 + fi));
                const fRot = corruptionAge * 360 * (rng(i * 15 + fi) > 0.5 ? 1 : -1);
                const fScale = interpolate(corruptionAge, [0, 0.5, 1], [1, 0.8, 0.3], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
                const fOpacity = interpolate(corruptionAge, [0.5, 1], [1, 0.2], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
                return (
                  <div key={fi} style={{
                    position: "absolute",
                    left: baseX + (fi % 2) * fragSize + Math.cos(fAngle) * fDist,
                    top: baseY + Math.floor(fi / 2) * fragSize + Math.sin(fAngle) * fDist,
                    width: fragSize,
                    height: fragSize,
                    backgroundColor: cell.corruptColor,
                    transform: `rotate(${fRot}deg) scale(${fScale})`,
                    opacity: fOpacity,
                  }} />
                );
              })}
            </React.Fragment>
          );
        }

        if (behavior === 2) {
          const vibrate = Math.sin(frame * (3 + rng(i * 17) * 10)) * corruptionAge * 4;
          const vibrateY = Math.cos(frame * (4 + rng(i * 19) * 8)) * corruptionAge * 4;
          const invertBg = frame % (Math.max(2, Math.round(8 - corruptionAge * 6))) < (Math.max(1, Math.round(4 - corruptionAge * 3)))
            ? cell.corruptColor : cell.sterileColor;
          return (
            <div key={i} style={{
              position: "absolute",
              left: baseX + vibrate,
              top: baseY + vibrateY,
              width: CELL_W - 1,
              height: CELL_H - 1,
              backgroundColor: invertBg,
              filter: corruptionAge > 0.5 ? `hue-rotate(${frame * 10}deg)` : "none",
              borderRadius: 1,
            }} />
          );
        }

        if (behavior === 3) {
          const stretchH = interpolate(corruptionAge, [0, 0.5, 1], [CELL_H - 1, CELL_H * 4, maxHeight * 0.8], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
          const stretchW = interpolate(corruptionAge, [0, 1], [CELL_W - 1, 2], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
          const stretchOpacity = interpolate(corruptionAge, [0, 0.3, 1], [1, 0.7, 0.3], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
          return (
            <div key={i} style={{
              position: "absolute",
              left: baseX + (CELL_W - stretchW) / 2,
              top: baseY - (stretchH - CELL_H) / 2,
              width: stretchW,
              height: stretchH,
              backgroundColor: cell.corruptColor,
              opacity: stretchOpacity,
              borderRadius: 1,
            }} />
          );
        }

        return (
          <div key={i} style={{
            position: "absolute",
            left: baseX,
            top: baseY,
            width: CELL_W - 1,
            height: CELL_H - 1,
            backgroundColor: cell.corruptColor,
            opacity: corruptionAge,
            borderRadius: 1,
          }} />
        );
      })}

      {corruptionSpread > 0 && corruptionSpread < 0.3 && (
        <div style={{
          position: "absolute",
          left: ORIGIN_COL * CELL_W - 10,
          top: ORIGIN_ROW * CELL_H - 10,
          width: CELL_W + 20,
          height: CELL_H + 20,
          borderRadius: "50%",
          boxShadow: `0 0 ${20 + Math.sin(frame * 0.5) * 10}px ${10}px rgba(57, 255, 20, 0.4)`,
          pointerEvents: "none",
        }} />
      )}
    </div>
  );
};

