export const WireframeLandscape: React.FC<any> = (props) => {
  const { position = { x: 0, y: 0, w: 1, h: 1 } } = props;
  const frame = useCurrentFrame();
  const { fps, durationInFrames, width, height } = useVideoConfig();

  const fadeOutStart = durationInFrames - Math.round(fps * 0.5);
  const exitOpacity = interpolate(
    frame,
    [fadeOutStart, durationInFrames],
    [1, 0],
    { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
  );

  const left = position.x * width;
  const top = position.y * height;
  const maxWidth = position.w * width;
  const maxHeight = position.h * height;

  const LINE_COLOR = "#4af0ff";
  const LINE_COLOR_DIM = "#1a6a7a";
  const GRID_COLS = 48;
  const GRID_ROWS = 32;
  const CELL_W = maxWidth / GRID_COLS;
  const CELL_H = maxHeight / GRID_ROWS;

  const t = frame / fps;
  const totalDuration = durationInFrames / fps;

  // Phase timing
  const calmEnd = totalDuration * 0.15;
  const pushStart = totalDuration * 0.15;
  const pushPeak = totalDuration * 0.45;
  const snapPhase = totalDuration * 0.5;
  const recedeStart = totalDuration * 0.55;
  const healStart = totalDuration * 0.65;
  const healEnd = totalDuration * 0.85;

  // Pressure points
  const pressurePoints = useMemo(() => [
    { cx: GRID_COLS * 0.3, cy: GRID_ROWS * 0.4, strength: 1.0, phase: 0 },
    { cx: GRID_COLS * 0.65, cy: GRID_ROWS * 0.55, strength: 0.8, phase: 0.4 },
    { cx: GRID_COLS * 0.5, cy: GRID_ROWS * 0.25, strength: 0.6, phase: 0.7 },
    { cx: GRID_COLS * 0.8, cy: GRID_ROWS * 0.3, strength: 0.5, phase: 0.2 },
    { cx: GRID_COLS * 0.15, cy: GRID_ROWS * 0.7, strength: 0.7, phase: 0.55 },
  ], []);

  // Pseudo-random seeded
  const seededRand = (seed: number) => {
    const x = Math.sin(seed * 127.1 + 311.7) * 43758.5453;
    return x - Math.floor(x);
  };

  // Broken lines tracking
  const brokenLines = useMemo(() => {
    const broken: { col: number; row: number; dir: 'h' | 'v'; breakTime: number; healTime: number }[] = [];
    for (let r = 0; r < GRID_ROWS; r++) {
      for (let c = 0; c < GRID_COLS; c++) {
        const seed = r * GRID_COLS + c;
        const rand = seededRand(seed);
        // Lines near pressure points are more likely to break
        let maxStress = 0;
        for (const pp of pressurePoints) {
          const dx = c - pp.cx;
          const dy = r - pp.cy;
          const dist = Math.sqrt(dx * dx + dy * dy);
          const stress = pp.strength / (1 + dist * 0.15);
          maxStress = Math.max(maxStress, stress);
        }
        if (rand < maxStress * 0.3 && maxStress > 0.3) {
          const breakT = snapPhase * 0.8 + rand * snapPhase * 0.4;
          const healT = healStart + rand * (healEnd - healStart);
          broken.push({
            col: c,
            row: r,
            dir: seededRand(seed + 999) > 0.5 ? 'h' : 'v',
            breakTime: breakT,
            healTime: healT,
          });
        }
      }
    }
    return broken;
  }, []);

  const brokenSet = useMemo(() => {
    const set = new Set<string>();
    for (const b of brokenLines) {
      set.add(`${b.col},${b.row},${b.dir}`);
    }
    return set;
  }, [brokenLines]);

  const getLineState = (col: number, row: number, dir: 'h' | 'v') => {
    const key = `${col},${row},${dir}`;
    const found = brokenLines.find(b => `${b.col},${b.row},${b.dir}` === key);
    if (!found) return { broken: false, opacity: 1, whipOffset: 0 };

    const isBroken = t > found.breakTime;
    const isHealed = t > found.healTime;

    if (!isBroken) return { broken: false, opacity: 1, whipOffset: 0 };
    if (isHealed) {
      const healProgress = interpolate(t, [found.healTime, found.healTime + 0.5], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
      return { broken: false, opacity: healProgress * 0.7, whipOffset: 0, healed: true };
    }

    const breakProgress = interpolate(t, [found.breakTime, found.breakTime + 0.3], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
    const whip = Math.sin(breakProgress * Math.PI * 4) * (1 - breakProgress) * 30;
    return { broken: true, opacity: 1 - breakProgress, whipOffset: whip };
  };

  // Height function
  const getHeight = (col: number, row: number) => {
    // Base calm ocean
    const breathPhase = t > healEnd ? 1 : 0;
    const arrhythmiaOffset = breathPhase > 0 ? Math.sin(col * 0.3 + t * 1.7) * 0.3 : 0;
    const baseWave = Math.sin(col * 0.15 + t * 0.8 + arrhythmiaOffset) * Math.cos(row * 0.12 + t * 0.6) * 3;

    // Breathing with arrhythmia after heal
    let breathMultiplier = 1;
    if (t > healEnd) {
      const irregularBreath = Math.sin(t * 2.5) * 0.5 + Math.sin(t * 1.3) * 0.3 + Math.sin(t * 4.1) * 0.2;
      breathMultiplier = 1 + irregularBreath * 0.3;
    }

    // Pressure bumps
    let bump = 0;
    const pushProgress = interpolate(t, [pushStart, pushPeak], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
    const recedeProgress = interpolate(t, [recedeStart, healStart], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
    const bumpIntensity = pushProgress * (1 - recedeProgress * 0.85);

    for (const pp of pressurePoints) {
      const dx = col - pp.cx;
      const dy = row - pp.cy;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const radius = 8;
      const ppDelay = pp.phase * 0.5;
      const ppProgress = interpolate(t, [pushStart + ppDelay, pushPeak + ppDelay * 0.5], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
      const ppRecede = interpolate(t, [recedeStart + ppDelay * 0.3, healStart], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
      const intensity = ppProgress * (1 - ppRecede * 0.8) * pp.strength;
      const falloff = Math.exp(-(dist * dist) / (radius * radius));
      bump += falloff * intensity * 35;
    }

    // After healing, geometry is slightly wrong
    let wrongness = 0;
    if (t > healEnd) {
      const wrongProgress = interpolate(t, [healEnd, healEnd + 1], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
      wrongness = (seededRand(col * 31 + row * 71) - 0.5) * 4 * wrongProgress;
    }

    return (baseWave * breathMultiplier + bump + wrongness);
  };

  // Generate SVG paths
  const paths = useMemo(() => {
    const result: { d: string; opacity: number; color: string; strokeWidth: number }[] = [];

    // Horizontal lines
    for (let r = 0; r <= GRID_ROWS; r++) {
      for (let c = 0; c < GRID_COLS; c++) {
        const state = getLineState(c, r, 'h');

        const h1 = getHeight(c, r);
        const h2 = getHeight(c + 1, r);

        const x1 = c * CELL_W;
        const y1 = r * CELL_H - h1;
        const x2 = (c + 1) * CELL_W;
        const y2 = r * CELL_H - h2;

        if (state.broken && state.opacity <= 0) continue;

        const avgH = (Math.abs(h1) + Math.abs(h2)) / 2;
        const stretch = interpolate(avgH, [0, 25], [1, 0.2], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
        const lineOpacity = state.opacity * stretch;

        if (lineOpacity < 0.02) continue;

        const whipY = state.broken ? state.whipOffset : 0;
        const midX = (x1 + x2) / 2;
        const midY = (y1 + y2) / 2 + whipY;

        const sw = interpolate(stretch, [0.2, 1], [0.3, 0.8], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });

        result.push({
          d: state.broken
            ? `M${x1},${y1}Q${midX},${midY},${x2},${y2}`
            : `M${x1},${y1}L${x2},${y2}`,
          opacity: lineOpacity,
          color: stretch < 0.5 ? LINE_COLOR_DIM : LINE_COLOR,
          strokeWidth: (state as any).healed ? sw * 0.6 : sw,
        });
      }
    }

    // Vertical lines
    for (let c = 0; c <= GRID_COLS; c++) {
      for (let r = 0; r < GRID_ROWS; r++) {
        const state = getLineState(c, r, 'v');

        const h1 = getHeight(c, r);
        const h2 = getHeight(c, r + 1);

        const x1 = c * CELL_W;
        const y1 = r * CELL_H - h1;
        const x2 = c * CELL_W;
        const y2 = (r + 1) * CELL_H - h2;

        if (state.broken && state.opacity <= 0) continue;

        const avgH = (Math.abs(h1) + Math.abs(h2)) / 2;
        const stretch = interpolate(avgH, [0, 25], [1, 0.2], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
        const lineOpacity = state.opacity * stretch;

        if (lineOpacity < 0.02) continue;

        const whipX = state.broken ? state.whipOffset : 0;
        const midX = (x1 + x2) / 2 + whipX;
        const midY = (y1 + y2) / 2;

        const sw = interpolate(stretch, [0.2, 1], [0.3, 0.8], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });

        result.push({
          d: state.broken
            ? `M${x1},${y1}Q${midX},${midY},${x2},${y2}`
            : `M${x1},${y1}L${x2},${y2}`,
          opacity: lineOpacity,
          color: stretch < 0.5 ? LINE_COLOR_DIM : LINE_COLOR,
          strokeWidth: (state as any).healed ? sw * 0.6 : sw,
        });
      }
    }

    return result;
  }, [frame]);

  // Void holes - dark patches where lines broke
  const voidHoles = useMemo(() => {
    const holes: { cx: number; cy: number; r: number; opacity: number }[] = [];
    for (const b of brokenLines) {
      if (t <= b.breakTime) continue;
      const healProgress = t > b.healTime
        ? interpolate(t, [b.healTime, b.healTime + 1], [1, 0], { extrapolateLeft: "clamp", extrapolateRight: "clamp" })
        : 1;
      const breakAge = interpolate(t, [b.breakTime, b.breakTime + 0.5], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
      if (healProgress <= 0) continue;
      holes.push({
        cx: b.col * CELL_W + CELL_W * 0.5,
        cy: b.row * CELL_H - getHeight(b.col, b.row),
        r: CELL_W * 0.8 * breakAge * healProgress,
        opacity: 0.9 * healProgress,
      });
    }
    return holes;
  }, [frame]);

  // Glow intensity pulses
  const glowIntensity = t > healEnd
    ? 0.3 + Math.sin(t * 2.5) * 0.1 + Math.sin(t * 4.1) * 0.05
    : 0.4;

  return (
    <div
      style={{
        position: "absolute",
        left,
        top,
        width: maxWidth,
        height: maxHeight,
        overflow: "hidden",
        opacity: exitOpacity,
        background: "#000000",
      }}
    >
      <svg
        width={maxWidth}
        height={maxHeight}
        viewBox={`0 0 ${maxWidth} ${maxHeight}`}
        style={{ position: "absolute", top: 0, left: 0 }}
      >
        <defs>
          <filter id="glow-wire">
            <feGaussianBlur stdDeviation={1.5} result="blur" />
            <feMerge>
              <feMergeNode in="blur" />
              <feMergeNode in="SourceGraphic" />
            </feMerge>
          </filter>
          <radialGradient id="void-grad">
            <stop offset="0%" stopColor="#000000" stopOpacity={1} />
            <stop offset="70%" stopColor="#000000" stopOpacity={0.8} />
            <stop offset="100%" stopColor="#000000" stopOpacity={0} />
          </radialGradient>
        </defs>

        {/* Void holes beneath the mesh */}
        {voidHoles.map((hole, i) => (
          <circle
            key={`void-${i}`}
            cx={hole.cx}
            cy={hole.cy}
            r={hole.r}
            fill="url(#void-grad)"
            opacity={hole.opacity}
          />
        ))}

        {/* Wireframe mesh */}
        <g filter="url(#glow-wire)" opacity={glowIntensity + 0.6}>
          {paths.map((p, i) => (
            <path
              key={i}
              d={p.d}
              stroke={p.color}
              strokeWidth={p.strokeWidth}
              fill="none"
              opacity={p.opacity}
              strokeLinecap="round"
            />
          ))}
        </g>

        {/* Subtle ambient glow at pressure points */}
        {pressurePoints.map((pp, i) => {
          const ppProgress = interpolate(t, [pushStart + pp.phase * 0.5, pushPeak], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
          const ppRecede = interpolate(t, [recedeStart, healStart], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
          const glowOp = ppProgress * (1 - ppRecede) * pp.strength * 0.15;
          if (glowOp < 0.01) return null;
          return (
            <circle
              key={`glow-${i}`}
              cx={pp.cx * CELL_W}
              cy={pp.cy * CELL_H}
              r={CELL_W * 6}
              fill={LINE_COLOR}
              opacity={glowOp}
              filter="url(#glow-wire)"
            />
          );
        })}
      </svg>

      {/* Deep black overlay for depth illusion at void points */}
      <div
        style={{
          position: "absolute",
          top: 0,
          left: 0,
          width: "100%",
          height: "100%",
          pointerEvents: "none",
          background: "radial-gradient(ellipse at center, transparent 60%, rgba(0,0,0,0.3) 100%)",
        }}
      />
    </div>
  );
};

