export const TerminalChaos: React.FC<any> = (props) => {
  const { position = { x: 0, y: 0, w: 1, h: 1 } } = props;
  const frame = useCurrentFrame();
  const { fps, durationInFrames, width, height } = useVideoConfig();

  const left = position.x * width;
  const top = position.y * height;
  const maxWidth = position.w * width;
  const maxHeight = position.h * height;

  const fadeOutStart = durationInFrames - Math.round(fps * 0.5);
  const exitOpacity = interpolate(
    frame,
    [fadeOutStart, durationInFrames],
    [1, 0],
    { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
  );

  // Timing phases
  const CHAR_SIZE = 18;
  const cols = Math.floor(maxWidth / CHAR_SIZE);
  const rows = Math.floor(maxHeight / (CHAR_SIZE * 1.4));
  const totalCells = cols * rows;

  const SNAP_LETTER = "X";
  const SNAP_HOLD = 10;
  const ASH_DURATION = Math.round(fps * 1.2);
  const snapStart = durationInFrames - Math.round(fps * 0.5) - SNAP_HOLD - ASH_DURATION;
  const snapEnd = snapStart + SNAP_HOLD;
  const ashEnd = snapEnd + ASH_DURATION;

  const chaosStart = Math.round(durationInFrames * 0.55);
  const peakChaos = snapStart;

  const RANDOM_CHARS = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789!@#$%^&*()_+-=[]{}|;:',.<>?/~`";
  const WORD_FRAGMENTS = [
    "sys", "err", "buf", "mem", "null", "void", "core", "seg",
    "fault", "init", "load", "exec", "kill", "dump", "halt",
    "over", "flow", "stack", "heap", "alloc", "free", "ptr",
    "addr", "bit", "byte", "root", "node", "link", "port",
    "die", "exit", "fail", "warn", "log", "run", "end"
  ];

  // Deterministic pseudo-random
  const seed = useMemo(() => {
    const s: number[] = [];
    let v = 42;
    for (let i = 0; i < 5000; i++) {
      v = (v * 1664525 + 1013904223) & 0xFFFFFFFF;
      s.push((v >>> 0) / 0xFFFFFFFF);
    }
    return s;
  }, []);

  const rng = (i: number) => seed[((i % seed.length) + seed.length) % seed.length];

  // Build the grid of characters that appear over time
  const gridData = useMemo(() => {
    const cells: Array<{
      col: number;
      row: number;
      appearFrame: number;
      char: string;
      isFragment: boolean;
      fragmentId: number;
      rndSeed: number;
    }> = [];

    // Place word fragments at random positions
    const fragments: Array<{ word: string; col: number; row: number; appearBase: number }> = [];
    for (let i = 0; i < 30; i++) {
      const word = WORD_FRAGMENTS[Math.floor(rng(i * 7) * WORD_FRAGMENTS.length)];
      const col = Math.floor(rng(i * 7 + 1) * (cols - word.length));
      const row = Math.floor(rng(i * 7 + 2) * rows);
      const appearBase = Math.floor(rng(i * 7 + 3) * chaosStart * 0.8) + Math.round(fps * 0.5);
      fragments.push({ word, col, row, appearBase });
    }

    const occupiedMap = new Map<string, number>();

    // Add fragment characters
    fragments.forEach((frag, fi) => {
      for (let ci = 0; ci < frag.word.length; ci++) {
        const key = `${frag.col + ci},${frag.row}`;
        if (!occupiedMap.has(key) || occupiedMap.get(key)! > frag.appearBase + ci * 3) {
          occupiedMap.set(key, frag.appearBase + ci * 3);
          cells.push({
            col: frag.col + ci,
            row: frag.row,
            appearFrame: frag.appearBase + ci * 3,
            char: frag.word[ci],
            isFragment: true,
            fragmentId: fi,
            rndSeed: fi * 100 + ci,
          });
        }
      }
    });

    // Fill remaining cells with random chars, accelerating appearance
    let cellIndex = 0;
    for (let r = 0; r < rows; r++) {
      for (let c = 0; c < cols; c++) {
        const key = `${c},${r}`;
        if (!occupiedMap.has(key)) {
          const linearT = cellIndex / totalCells;
          // Accelerating curve: chars appear faster over time
          const t = Math.pow(linearT, 0.6);
          const appearFrame = Math.floor(t * (peakChaos - 5)) + Math.floor(rng(cellIndex * 3 + 100) * 8);
          const charIdx = Math.floor(rng(cellIndex * 3 + 200) * RANDOM_CHARS.length);
          cells.push({
            col: c,
            row: r,
            appearFrame: Math.min(appearFrame, peakChaos),
            char: RANDOM_CHARS[charIdx],
            isFragment: false,
            fragmentId: -1,
            rndSeed: cellIndex,
          });
        }
        cellIndex++;
      }
    }

    return cells;
  }, [cols, rows, totalCells, chaosStart, peakChaos]);

  // Misbehaving characters (chaos phase)
  const misbehaviors = useMemo(() => {
    const items: Array<{
      col: number;
      row: number;
      type: "stretch-g" | "inflate-O" | "flicker";
      startFrame: number;
      char1?: string;
      char2?: string;
    }> = [];

    // Stretching 'g'
    for (let i = 0; i < 3; i++) {
      items.push({
        col: Math.floor(rng(800 + i) * cols),
        row: Math.floor(rng(810 + i) * (rows * 0.4)),
        type: "stretch-g",
        startFrame: chaosStart + Math.floor(rng(820 + i) * (peakChaos - chaosStart) * 0.5),
      });
    }

    // Inflating 'O'
    for (let i = 0; i < 2; i++) {
      items.push({
        col: Math.floor(rng(900 + i) * (cols - 4)) + 2,
        row: Math.floor(rng(910 + i) * (rows - 4)) + 2,
        type: "inflate-O",
        startFrame: chaosStart + Math.floor(rng(920 + i) * (peakChaos - chaosStart) * 0.6),
      });
    }

    // Flickering pairs
    for (let i = 0; i < 8; i++) {
      const c1Idx = Math.floor(rng(1000 + i * 3) * RANDOM_CHARS.length);
      const c2Idx = Math.floor(rng(1001 + i * 3) * RANDOM_CHARS.length);
      items.push({
        col: Math.floor(rng(1002 + i * 3) * cols),
        row: Math.floor(rng(1003 + i * 3) * rows),
        type: "flicker",
        startFrame: chaosStart + Math.floor(rng(1004 + i * 3) * (peakChaos - chaosStart) * 0.7),
        char1: RANDOM_CHARS[c1Idx],
        char2: RANDOM_CHARS[c2Idx],
      });
    }

    return items;
  }, [chaosStart, peakChaos, cols, rows]);

  // Phase determination
  const isSnap = frame >= snapStart && frame < snapEnd;
  const isAsh = frame >= snapEnd && frame < ashEnd;
  const isPreSnap = frame < snapStart;

  // Ash particles
  const ashParticles = useMemo(() => {
    return gridData.map((cell, i) => ({
      x: cell.col * CHAR_SIZE + rng(i * 5 + 3000) * 4 - 2,
      y: cell.row * CHAR_SIZE * 1.4,
      vx: (rng(i * 5 + 3001) - 0.5) * 60,
      vy: 40 + rng(i * 5 + 3002) * 120,
      rotation: (rng(i * 5 + 3003) - 0.5) * 720,
      size: 1 + rng(i * 5 + 3004) * 3,
      delay: rng(i * 5 + 3005) * 8,
    }));
  }, [gridData]);

  const lineHeight = CHAR_SIZE * 1.4;

  // Render misbehaviors overlay
  const renderMisbehaviors = () => {
    if (!isPreSnap) return null;
    const chaosProgress = interpolate(frame, [chaosStart, peakChaos], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
    if (chaosProgress <= 0) return null;

    return misbehaviors.map((m, i) => {
      if (frame < m.startFrame) return null;
      const localFrame = frame - m.startFrame;
      const mProgress = spring({ frame: localFrame, fps, config: { damping: 12, mass: 0.8, stiffness: 60 } });

      if (m.type === "stretch-g") {
        const stretchHeight = interpolate(mProgress, [0, 1], [lineHeight, maxHeight - m.row * lineHeight]);
        return (
          <div
            key={`mis-${i}`}
            style={{
              position: "absolute",
              left: m.col * CHAR_SIZE,
              top: m.row * lineHeight,
              width: CHAR_SIZE,
              height: stretchHeight,
              fontFamily: "'Courier New', Courier, monospace",
              fontSize: CHAR_SIZE,
              color: "#00FF41",
              overflow: "visible",
              display: "flex",
              alignItems: "flex-start",
              justifyContent: "center",
              zIndex: 10,
              transform: `scaleY(${stretchHeight / lineHeight})`,
              transformOrigin: "top center",
            }}
          >
            g
          </div>
        );
      }

      if (m.type === "inflate-O") {
        const inflateSize = interpolate(mProgress, [0, 1], [CHAR_SIZE, CHAR_SIZE * 12]);
        const oOpacity = interpolate(mProgress, [0, 0.3, 1], [1, 0.9, 0.7], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
        return (
          <div
            key={`mis-${i}`}
            style={{
              position: "absolute",
              left: m.col * CHAR_SIZE + CHAR_SIZE / 2 - inflateSize / 2,
              top: m.row * lineHeight + lineHeight / 2 - inflateSize / 2,
              width: inflateSize,
              height: inflateSize,
              borderRadius: "50%",
              border: `2px solid #00FF41`,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              fontFamily: "'Courier New', Courier, monospace",
              fontSize: inflateSize * 0.7,
              color: "#00FF41",
              opacity: oOpacity,
              zIndex: 15,
              backgroundColor: "rgba(0,0,0,0.8)",
            }}
          >
            O
          </div>
        );
      }

      if (m.type === "flicker") {
        const flickerRate = 3;
        const showFirst = Math.floor(frame / flickerRate) % 2 === 0;
        return (
          <div
            key={`mis-${i}`}
            style={{
              position: "absolute",
              left: m.col * CHAR_SIZE,
              top: m.row * lineHeight,
              width: CHAR_SIZE,
              height: lineHeight,
              fontFamily: "'Courier New', Courier, monospace",
              fontSize: CHAR_SIZE,
              color: showFirst ? "#FF4444" : "#44FF44",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              zIndex: 10,
              textShadow: `0 0 8px ${showFirst ? "#FF4444" : "#44FF44"}`,
            }}
          >
            {showFirst ? m.char1 : m.char2}
          </div>
        );
      }

      return null;
    });
  };

  // Render ash particles
  const renderAsh = () => {
    if (!isAsh) return null;
    const ashFrame = frame - snapEnd;

    return ashParticles.map((p, i) => {
      if (i % 3 !== 0) return null; // Render every 3rd for performance
      const localFrame = Math.max(0, ashFrame - p.delay);
      if (localFrame <= 0) return null;
      const t = localFrame / fps;
      const x = p.x + p.vx * t;
      const y = p.y + p.vy * t + 200 * t * t;
      const rot = p.rotation * t;
      const opacity = interpolate(localFrame, [0, ASH_DURATION * 0.3, ASH_DURATION], [1, 0.6, 0], { extrapolateRight: "clamp" });

      if (opacity <= 0 || y > maxHeight + 20) return null;

      return (
        <div
          key={`ash-${i}`}
          style={{
            position: "absolute",
            left: x,
            top: y,
            width: p.size,
            height: p.size,
            backgroundColor: `rgba(0, 255, 65, ${opacity})`,
            borderRadius: 1,
            transform: `rotate(${rot}deg)`,
            boxShadow: `0 0 ${p.size}px rgba(0, 255, 65, ${opacity * 0.5})`,
          }}
        />
      );
    });
  };

  // Render grid characters
  const renderGrid = () => {
    if (isAsh) return null;

    const chaosProgress = interpolate(frame, [chaosStart, peakChaos], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });

    // For snap, render all as same letter
    if (isSnap) {
      const snapProgress = spring({ frame: frame - snapStart, fps, config: { damping: 20, mass: 0.5, stiffness: 200 } });
      return (
        <div style={{ opacity: snapProgress }}>
          {Array.from({ length: rows }, (_, r) => (
            <div key={r} style={{ display: "flex", height: lineHeight }}>
              {Array.from({ length: cols }, (_, c) => (
                <div
                  key={c}
                  style={{
                    width: CHAR_SIZE,
                    height: lineHeight,
                    fontFamily: "'Courier New', Courier, monospace",
                    fontSize: CHAR_SIZE,
                    color: "#00FF41",
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    textShadow: "0 0 10px #00FF41, 0 0 20px #00FF41",
                  }}
                >
                  {SNAP_LETTER}
                </div>
              ))}
            </div>
          ))}
        </div>
      );
    }

    // Pre-snap: render appearing characters
    const visibleCells = gridData.filter(cell => frame >= cell.appearFrame);

    // Build a grid map for fast lookup
    const gridMap = new Map<string, typeof gridData[0]>();
    visibleCells.forEach(cell => {
      const key = `${cell.col},${cell.row}`;
      const existing = gridMap.get(key);
      if (!existing || cell.appearFrame > existing.appearFrame) {
        gridMap.set(key, cell);
      }
    });

    return Array.from({ length: rows }, (_, r) => (
      <div key={r} style={{ display: "flex", height: lineHeight }}>
        {Array.from({ length: cols }, (_, c) => {
          const key = `${c},${r}`;
          const cell = gridMap.get(key);
          if (!cell) {
            return <div key={c} style={{ width: CHAR_SIZE, height: lineHeight }} />;
          }

          const age = frame - cell.appearFrame;
          const enterOpacity = interpolate(age, [0, 3], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });

          // During chaos, some characters jitter
          let jitterX = 0;
          let jitterY = 0;
          if (chaosProgress > 0.3) {
            const jitterAmount = (chaosProgress - 0.3) * 4;
            jitterX = (rng(cell.rndSeed * 11 + frame) - 0.5) * jitterAmount;
            jitterY = (rng(cell.rndSeed * 13 + frame) - 0.5) * jitterAmount;
          }

          // Color: fragments are brighter
          const baseColor = cell.isFragment ? "#00FF99" : "#00FF41";
          const glowIntensity = cell.isFragment ? 6 : 2;
          const charOpacity = enterOpacity * (chaosProgress > 0.7 ? (0.5 + rng(cell.rndSeed + frame * 7) * 0.5) : 1);

          return (
            <div
              key={c}
              style={{
                width: CHAR_SIZE,
                height: lineHeight,
                fontFamily: "'Courier New', Courier, monospace",
                fontSize: CHAR_SIZE,
                color: baseColor,
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                opacity: charOpacity,
                transform: `translate(${jitterX}px, ${jitterY}px)`,
                textShadow: `0 0 ${glowIntensity}px ${baseColor}`,
              }}
            >
              {cell.char}
            </div>
          );
        })}
      </div>
    ));
  };

  // Scanline effect
  const scanlineY = (frame * 3) % maxHeight;

  return (
    <div
      style={{
        position: "absolute",
        left,
        top,
        width: maxWidth,
        height: maxHeight,
        overflow: "hidden",
        opacity: exitOpacity,
        backgroundColor: "rgba(0, 0, 0, 0.92)",
      }}
    >
      {/* CRT scanlines overlay */}
      <div
        style={{
          position: "absolute",
          top: 0,
          left: 0,
          width: "100%",
          height: "100%",
          background: `repeating-linear-gradient(
            0deg,
            transparent,
            transparent ${lineHeight - 1}px,
            rgba(0, 255, 65, 0.03) ${lineHeight - 1}px,
            rgba(0, 255, 65, 0.03) ${lineHeight}px
          )`,
          zIndex: 20,
          pointerEvents: "none",
        }}
      />

      {/* Moving scanline */}
      <div
        style={{
          position: "absolute",
          top: scanlineY,
          left: 0,
          width: "100%",
          height: 2,
          backgroundColor: "rgba(0, 255, 65, 0.15)",
          zIndex: 21,
          pointerEvents: "none",
          boxShadow: "0 0 20px rgba(0, 255, 65, 0.1)",
        }}
      />

      {/* Screen flicker */}
      <div
        style={{
          position: "absolute",
          top: 0,
          left: 0,
          width: "100%",
          height: "100%",
          backgroundColor: `rgba(0, 255, 65, ${0.01 + rng(frame * 17) * 0.02})`,
          zIndex: 19,
          pointerEvents: "none",
        }}
      />

      {/* Main grid content */}
      <div style={{ position: "relative", zIndex: 5 }}>
        {renderGrid()}
      </div>

      {/* Misbehaviors overlay */}
      <div style={{ position: "absolute", top: 0, left: 0, zIndex: 10 }}>
        {renderMisbehaviors()}
      </div>

      {/* Ash particles */}
      <div style={{ position: "absolute", top: 0, left: 0, width: "100%", height: "100%", zIndex: 5 }}>
        {renderAsh()}
      </div>

      {/* Vignette */}
      <div
        style={{
          position: "absolute",
          top: 0,
          left: 0,
          width: "100%",
          height: "100%",
          background: "radial-gradient(ellipse at center, transparent 50%, rgba(0,0,0,0.6) 100%)",
          zIndex: 22,
          pointerEvents: "none",
        }}
      />
    </div>
  );
};
